mapper.sql:
and a.recovery = 0 and a.sign_score >0
and a.store_id = #{store_id}
and a.type = #{type}
and b.source = #{source}
and a.user_id = #{user_id}


    and a.sNo like concat('%', #{sNo}, '%')



    and a.sign_time  >=  concat(#{signTime}, '-01 00:00:00')
    and a.sign_time  <  date_add(concat(#{signTime}, '-01 00:00:00'), interval 1 month)

and a.sign_time  >=  #{sign_time_start}
and a.sign_time  <  #{sign_time_end}
and a.sign_time  <=  #{sign_time_end1}
and(b.user_id like concat('%',#{userName},'%') or
    b.zhanghao like concat('%',#{userName},'%') or b.mobile like concat('%',#{userName},'%'))


    
        #{type,jdbcType=INTEGER}
    


    
        #{id,jdbcType=INTEGER}

mapper.select:
select * from lkt_sign_record a
a.sign_time ${sign_time_sort},
limit #{pageStart},#{pageEnd}

SELECT a.`id`, a.`store_id`, a.`user_id`, a.`sign_score`, a.`total_score`, a.`record`, a.`score_invalid`, a.`sign_time`, a.`type`, a.`recovery`, a.`sNo`, a.`frozen_time`, a.`notice` FROM ( SELECT max( a.sign_time ) over(partition by b.user_id) AS sign_time1, a.*, b.user_name, b.mobile, b.source, b.user_id AS b_userId, ROW_NUMBER() over(partition by b.user_id) AS top FROM lkt_sign_record AS a LEFT JOIN lkt_user AS b ON a.user_id = b.user_id AND a.store_id = b.store_id
b.user_id ${user_id_sort}, sign_time1 ${sign_time1_sort},
) AS a WHERE a.top < 2 limit #{pageStart},#{pageEnd}

select a.*,b.user_name,b.user_id as b_userId from lkt_sign_record as a left join lkt_user as b on a.user_id = b.user_id and a.store_id = b.store_id
b.user_id ${user_id_sort}, sign_time1 ${sign_time1_sort}, sign_time ${sign_time_sort},
limit #{pageStart},#{pageEnd}
